#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(int x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
CI MAXN=1e6+5;
int a[MAXN],n,m,cnt[MAXN],sum=1,minsum=inf,minl,minr;
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
    n=read(),m=read();
    for(int i=1;i<=n;++i)
    {
        a[i]=read();
    }
    int r=1,l=0;
    ++cnt[a[1]];
    while(r<=n)
    {
        if(sum<m)
        {
            if(cnt[a[r+1]]==0)
            {
                ++sum;
            }
            ++cnt[a[++r]];
        }
        else
        {
            if(r-l<minsum)
            {
                minsum=r-l;
                minl=l+1,minr=r;
            }
            if(cnt[a[l+1]]==1)
            {
                --sum;
            }
            --cnt[a[++l]];
        }

    }
    printf("%d %d",minl,minr);
	return false;
}
